   418→// Validate validates consistency between span and bucket slices. Also, buckets are checked
   419→// against negative values. We check to make sure there are no unexpected fields or field values
   420→// based on the exponential / custom buckets schema.
   421→// For histograms that have not observed any NaN values (based on IsNaN(h.Sum) check), a
   422→// strict h.Count = nCount + pCount + h.ZeroCount check is performed.
   423→// Otherwise, only a lower bound check will be done (h.Count >= nCount + pCount + h.ZeroCount),
   424→// because NaN observations do not increment the values of buckets (but they do increment
   425→// the total h.Count).
   426→func (h *Histogram) Validate() error {
   427→	var nCount, pCount uint64
   428→	switch {
   429→	case IsCustomBucketsSchema(h.Schema):
   430→		if err := checkHistogramCustomBounds(h.CustomValues, h.PositiveSpans, len(h.PositiveBuckets)); err != nil {
   431→			return fmt.Errorf("custom buckets: %w", err)
   432→		}
   433→		if h.ZeroCount != 0 {
   434→			return ErrHistogramCustomBucketsZeroCount
   435→		}
   436→		if h.ZeroThreshold != 0 {
   437→			return ErrHistogramCustomBucketsZeroThresh
   438→		}
   439→		if len(h.NegativeSpans) > 0 {
   440→			return ErrHistogramCustomBucketsNegSpans
   441→		}
   442→		if len(h.NegativeBuckets) > 0 {
   443→			return ErrHistogramCustomBucketsNegBuckets
   444→		}
   445→	case IsExponentialSchema(h.Schema):
   446→		if err := checkHistogramSpans(h.PositiveSpans, len(h.PositiveBuckets)); err != nil {
   447→			return fmt.Errorf("positive side: %w", err)
   448→		}
   449→		if err := checkHistogramSpans(h.NegativeSpans, len(h.NegativeBuckets)); err != nil {
   450→			return fmt.Errorf("negative side: %w", err)
   451→		}
   452→		err := checkHistogramBuckets(h.NegativeBuckets, &nCount, true)
   453→		if err != nil {
   454→			return fmt.Errorf("negative side: %w", err)
   455→		}
   456→		if h.CustomValues != nil {
   457→			return ErrHistogramExpSchemaCustomBounds
   458→		}
   459→	default:
   460→		return InvalidSchemaError(h.Schema)
   461→	}
   462→	err := checkHistogramBuckets(h.PositiveBuckets, &pCount, true)
   463→	if err != nil {
   464→		return fmt.Errorf("positive side: %w", err)
   465→	}
   466→
   467→	sumOfBuckets := nCount + pCount + h.ZeroCount
   468→	if math.IsNaN(h.Sum) {
   469→		if sumOfBuckets > h.Count {
   470→			return fmt.Errorf("%d observations found in buckets, but the Count field is %d: %w", sumOfBuckets, h.Count, ErrHistogramCountNotBigEnough)
   471→		}
   472→	} else {
   473→		if sumOfBuckets != h.Count {
   474→			return fmt.Errorf("%d observations found in buckets, but the Count field is %d: %w", sumOfBuckets, h.Count, ErrHistogramCountMismatch)
   475→		}
   476→	}
   477→
   478→	return nil
   479→}
